import bebidas from "./data-json/bebidas.json";
import TarjetaAmpliada from './tarjetas-simple-doble/tarjeta-ampliada';


function BebidasAmpliadas() {

    return (
        <div className='cont-beb-ampl'>
            {
                bebidas &&
                bebidas.map((elemento) => (
                    <TarjetaAmpliada key={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} />
                ))
            }
        </div>
    )
};



export default BebidasAmpliadas;
